script.text:
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {f.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function onchange$Deparment(o) {o.parentForm.request('Reference', 'Reference', ['ma_bp']);}

function on$Filter$ResponseComplete(f, e) {
var f = e.object, context = e.type.Context, result = e.type.Result;
switch (context) {
  case 'Reference':
    f.setItemControlBehavior('bp_ref', result[0].Value, true);
    break;
  case 'Checking':
    var g = f.grid, k = [];
    Array.add(k, {Name: 'ngay_hl_tu', Opr: '<=', Value: f.getItemValue('ngay_den'), Type: 'DateTime', Ignore: false});
    Array.add(k, {Name: 'ngay_hl_den is null or ngay_hl_den', Opr: '>=', Value: f.getItemValue('ngay_tu'), Type: 'DateTime', Ignore: false});

    if (f.getItemValue('ma_bp')) Array.add(k, {Name: 'bp_ref', Opr: 'like', Value: $func.trim(f.getItemValue('bp_ref')) + '%', Type: 'String', Ignore: false});
    if (f.getItemValue('ma_nv')) Array.add(k, {Name: 'ma_nv', Opr: '=', Value: f.getItemValue('ma_nv'), Type: 'String', Ignore: false});

    g.set_externalKey(k);
    break;
  default:
    break;
  }
}
/* </flatten> */
